class PermissionError(Exception):
    """Raised when an actor lacks the required role/permission."""


class ValidationError(Exception):
    """Raised when a resource is missing mandatory elements."""


class StateTransitionError(Exception):
    """Raised on an illegal resource state transition."""


class ConflictWarning:
    """Encapsulates a drug-allergy conflict warning."""

    def __init__(self, allergy_id: str, medication_code: str, severity: str):
        self.allergy_id = allergy_id
        self.medication_code = medication_code
        self.severity = severity  # "high" | "moderate" | "low"

    def __repr__(self):
        return (
            f"ConflictWarning(allergy={self.allergy_id}, "
            f"med={self.medication_code}, severity={self.severity})"
        )


class AllergyIntolerance:
    VALID_STATUSES = {"active", "inactive", "resolved"}
    VALID_CATEGORIES = {"food", "medication", "environment", "biologic"}
    VALID_CRITICALITY = {"low", "high", "unable-to-assess"}

    def __init__(
        self,
        patient_id: str,
        substance_code: str,
        substance_display: str,
        recorder_id: str,
        status: str = "active",
        category: str = "medication",
        criticality: str = "high",
        allergy_id: str | None = None,
    ):
        self.id = allergy_id or str(uuid.uuid4())
        self.patient_id = patient_id
        self.substance_code = substance_code
        self.substance_display = substance_display
        self.recorder_id = recorder_id
        self.status = status
        self.category = category
        self.criticality = criticality
        self.recorded_date = datetime.now(timezone.utc)

    def to_dict(self) -> dict:
        return {
            "resourceType": "AllergyIntolerance",
            "id": self.id,
            "patient": {"reference": f"Patient/{self.patient_id}"},
            "code": {
                "coding": [
                    {
                        "system": "http://www.nlm.nih.gov/research/umls/rxnorm",
                        "code": self.substance_code,
                        "display": self.substance_display,
                    }
                ]
            },
            "recorder": {"reference": f"Practitioner/{self.recorder_id}"},
            "clinicalStatus": {
                "coding": [
                    {
                        "system": "http://terminology.hl7.org/CodeSystem/allergyintolerance-clinical",
                        "code": self.status,
                    }
                ]
            },
            "category": [self.category],
            "criticality": self.criticality,
            "recordedDate": self.recorded_date.isoformat(),
        }


class MedicationRequest:
    VALID_STATUSES = {"draft", "active", "on-hold", "cancelled", "completed", "entered-in-error"}
    ALLOWED_TRANSITIONS = {
        "draft": {"active", "cancelled"},
        "active": {"on-hold", "cancelled", "completed"},
        "on-hold": {"active", "cancelled"},
        "cancelled": set(),
        "completed": set(),
        "entered-in-error": set(),
    }

    def __init__(
        self,
        patient_id: str,
        medication_code: str,
        medication_display: str,
        requester_id: str,
        status: str = "draft",
        request_id: str | None = None,
    ):
        self.id = request_id or str(uuid.uuid4())
        self.patient_id = patient_id
        self.medication_code = medication_code
        self.medication_display = medication_display
        self.requester_id = requester_id
        self.status = status
        self.authored_on = datetime.now(timezone.utc)
        self.conflict_warnings: list[ConflictWarning] = []

    def transition_to(self, new_status: str) -> None:
        allowed = self.ALLOWED_TRANSITIONS.get(self.status, set())
        if new_status not in allowed:
            raise StateTransitionError(
                f"Cannot transition MedicationRequest from '{self.status}' to '{new_status}'."
            )
        self.status = new_status


