class AllergyIntoleranceService:
    """Records and retrieves AllergyIntolerance resources."""

    def __init__(self, repo, permission_service, audit_service):
        self._repo = repo
        self._permissions = permission_service
        self._audit = audit_service

    # mandatory fields for a valid AllergyIntolerance
    MANDATORY_FIELDS = {"patient_id", "substance_code", "substance_display", "recorder_id"}

    def record_allergy(self, actor_id: str, payload: dict) -> AllergyIntolerance:
        """Create and persist an AllergyIntolerance."""
        if not self._permissions.can_write_allergy(actor_id):
            raise PermissionError(f"Actor '{actor_id}' lacks permission to record allergies.")

        missing = self.MANDATORY_FIELDS - payload.keys()
        if missing:
            raise ValidationError(f"Missing mandatory fields: {missing}")

        empty = {k for k in self.MANDATORY_FIELDS if not payload.get(k)}
        if empty:
            raise ValidationError(f"Mandatory fields must not be empty: {empty}")

        allergy = AllergyIntolerance(**payload)
        self._repo.save(allergy)
        self._audit.log("create", actor_id, allergy.id)
        return allergy

    def update_status(self, actor_id: str, allergy_id: str, new_status: str) -> AllergyIntolerance:
        if not self._permissions.can_write_allergy(actor_id):
            raise PermissionError(f"Actor '{actor_id}' lacks permission to update allergies.")

        allergy = self._repo.get(allergy_id)
        if allergy is None:
            raise ValueError(f"AllergyIntolerance '{allergy_id}' not found.")

        if new_status not in AllergyIntolerance.VALID_STATUSES:
            raise ValidationError(f"Invalid status: {new_status}")

        # "resolved" → "active" is a conflicting state transition in this domain
        if allergy.status == "resolved" and new_status == "active":
            raise StateTransitionError(
                "Cannot reactivate a resolved AllergyIntolerance; create a new record instead."
            )

        allergy.status = new_status
        self._repo.save(allergy)
        self._audit.log("update", actor_id, allergy_id)
        return allergy

    def get_active_allergies_for_patient(self, patient_id: str) -> list[AllergyIntolerance]:
        return self._repo.find_active_by_patient(patient_id)


class ConflictCheckService:
    """Checks a medication code against a patient's active allergies."""

    def __init__(self, allergy_service: AllergyIntoleranceService, drug_interaction_db):
        self._allergy_service = allergy_service
        self._drug_db = drug_interaction_db

    def check(self, patient_id: str, medication_code: str) -> list[ConflictWarning]:
        warnings: list[ConflictWarning] = []
        allergies = self._allergy_service.get_active_allergies_for_patient(patient_id)
        for allergy in allergies:
            severity = self._drug_db.interaction_severity(
                allergy.substance_code, medication_code
            )
            if severity:
                warnings.append(
                    ConflictWarning(
                        allergy_id=allergy.id,
                        medication_code=medication_code,
                        severity=severity,
                    )
                )
        return warnings


class MedicationRequestService:
    """Creates MedicationRequests and attaches conflict warnings."""

    MANDATORY_FIELDS = {"patient_id", "medication_code", "medication_display", "requester_id"}

    def __init__(self, repo, permission_service, conflict_service: ConflictCheckService, audit_service):
        self._repo = repo
        self._permissions = permission_service
        self._conflict_service = conflict_service
        self._audit = audit_service

    def create_request(self, actor_id: str, payload: dict) -> MedicationRequest:
        if not self._permissions.can_write_medication_request(actor_id):
            raise PermissionError(
                f"Actor '{actor_id}' lacks permission to create medication requests."
            )

        missing = self.MANDATORY_FIELDS - payload.keys()
        if missing:
            raise ValidationError(f"Missing mandatory fields: {missing}")

        empty = {k for k in self.MANDATORY_FIELDS if not payload.get(k)}
        if empty:
            raise ValidationError(f"Mandatory fields must not be empty: {empty}")

        med_req = MedicationRequest(**payload)
        # attach conflict warnings
        med_req.conflict_warnings = self._conflict_service.check(
            payload["patient_id"], payload["medication_code"]
        )
        self._repo.save(med_req)
        self._audit.log("create", actor_id, med_req.id)
        return med_req

    def update_status(self, actor_id: str, request_id: str, new_status: str) -> MedicationRequest:
        if not self._permissions.can_write_medication_request(actor_id):
            raise PermissionError(
                f"Actor '{actor_id}' lacks permission to update medication requests."
            )

        med_req = self._repo.get(request_id)
        if med_req is None:
            raise ValueError(f"MedicationRequest '{request_id}' not found.")

        med_req.transition_to(new_status)  # raises StateTransitionError on illegal move
        self._repo.save(med_req)
        self._audit.log("update", actor_id, request_id)
        return med_req


