class TestRecordAllergyIntolerance:
    """Happy-path and validation tests for AllergyIntolerance creation."""

    def test_clinician_can_record_allergy(
        self, allergy_service, clinician_id, valid_allergy_payload, mock_allergy_repo
    ):
        """A clinician with write permission records an allergy successfully."""
        allergy = allergy_service.record_allergy(clinician_id, valid_allergy_payload)

        assert allergy is not None
        assert allergy.patient_id == valid_allergy_payload["patient_id"]
        assert allergy.substance_code == valid_allergy_payload["substance_code"]
        assert allergy.recorder_id == clinician_id
        mock_allergy_repo.save.assert_called_once_with(allergy)

    def test_allergy_linked_to_correct_patient(
        self, allergy_service, clinician_id, valid_allergy_payload, patient_id
    ):
        """The recorded allergy references the supplied patient ID."""
        allergy = allergy_service.record_allergy(clinician_id, valid_allergy_payload)
        assert allergy.patient_id == patient_id

    def test_allergy_serialises_with_patient_reference(
        self, allergy_service, clinician_id, valid_allergy_payload, patient_id
    ):
        """FHIR dict contains a Patient reference in the expected format."""
        allergy = allergy_service.record_allergy(clinician_id, valid_allergy_payload)
        fhir = allergy.to_dict()
        assert fhir["patient"]["reference"] == f"Patient/{patient_id}"
        assert fhir["resourceType"] == "AllergyIntolerance"

    def test_audit_log_written_on_record(
        self, allergy_service, clinician_id, valid_allergy_payload, mock_audit
    ):
        """An audit entry is written when an allergy is recorded."""
        allergy = allergy_service.record_allergy(clinician_id, valid_allergy_payload)
        mock_audit.log.assert_called_once_with("create", clinician_id, allergy.id)

    def test_default_status_is_active(
        self, allergy_service, clinician_id, patient_id, clinician_id as recorder_id
    ):
        """An allergy created without an explicit status defaults to 'active'."""
        payload = {
            "patient_id": patient_id,
            "substance_code": "7980",
            "substance_display": "Penicillin",
            "recorder_id": recorder_id,
        }
        allergy = allergy_service.record_allergy(recorder_id, payload)
        assert allergy.status == "active"

    # --- Negative: permission denial ---

    def test_permission_denied_raises_permission_error(
        self,
        mock_allergy_repo,
        restrictive_permissions,
        mock_audit,
        clinician_id,
        valid_allergy_payload,
    ):
        """An actor without write permission cannot record an allergy."""
        svc = AllergyIntoleranceService(
            mock_allergy_repo, restrictive_permissions, mock_audit
        )
        with pytest.raises(PermissionError, match=clinician_id):
            svc.record_allergy(clinician_id, valid_allergy_payload)

    def test_no_repo_save_on_permission_denied(
        self,
        mock_allergy_repo,
        restrictive_permissions,
        mock_audit,
        clinician_id,
        valid_allergy_payload,
    ):
        """Repository is NOT called when permission is denied."""
        svc = AllergyIntoleranceService(
            mock_allergy_repo, restrictive_permissions, mock_audit
        )
        with pytest.raises(PermissionError):
            svc.record_allergy(clinician_id, valid_allergy_payload)
        mock_allergy_repo.save.assert_not_called()

    def test_no_audit_log_on_permission_denied(
        self,
        mock_allergy_repo,
        restrictive_permissions,
        mock_audit,
        clinician_id,
        valid_allergy_payload,
    ):
        """Audit log is NOT written when permission is denied."""
        svc = AllergyIntoleranceService(
            mock_allergy_repo, restrictive_permissions, mock_audit
        )
        with pytest.raises(PermissionError):
            svc.record_allergy(clinician_id, valid_allergy_payload)
        mock_audit.log.assert_not_called()

    # --- Negative: missing mandatory elements ---

    @pytest.mark.parametrize("missing_field", [
        "patient_id",
        "substance_code",
        "substance_display",
        "recorder_id",
    ])
    def test_missing_mandatory_field_raises_validation_error(
        self, allergy_service, clinician_id, valid_allergy_payload, missing_field
    ):
        """Each mandatory field, when absent, causes a ValidationError."""
        payload = {k: v for k, v in valid_allergy_payload.items() if k != missing_field}
        with pytest.raises(ValidationError, match=missing_field):
            allergy_service.record_allergy(clinician_id, payload)

    @pytest.mark.parametrize("empty_field", [
        "patient_id",
        "substance_code",
        "substance_display",
        "recorder_id",
    ])
    def test_empty_mandatory_field_raises_validation_error(
        self, allergy_service, clinician_id, valid_allergy_payload, empty_field
    ):
        """Mandatory fields present but empty/blank raise ValidationError."""
        payload = {**valid_allergy_payload, empty_field: ""}
        with pytest.raises(ValidationError):
            allergy_service.record_allergy(clinician_id, payload)

    def test_none_patient_id_raises_validation_error(
        self, allergy_service, clinician_id, valid_allergy_payload
    ):
        """A None patient_id is treated as missing."""
        payload = {**valid_allergy_payload, "patient_id": None}
        with pytest.raises(ValidationError):
            allergy_service.record_allergy(clinician_id, payload)


