class TestAllergyStatusTransition:
    """State-machine tests for AllergyIntolerance status updates."""

    def _record(self, service, clinician_id, payload) -> AllergyIntolerance:
        return service.record_allergy(clinician_id, payload)

    def test_active_to_resolved_succeeds(
        self, allergy_service, clinician_id, valid_allergy_payload
    ):
        allergy = self._record(allergy_service, clinician_id, valid_allergy_payload)
        updated = allergy_service.update_status(clinician_id, allergy.id, "resolved")
        assert updated.status == "resolved"

    def test_active_to_inactive_succeeds(
        self, allergy_service, clinician_id, valid_allergy_payload
    ):
        allergy = self._record(allergy_service, clinician_id, valid_allergy_payload)
        updated = allergy_service.update_status(clinician_id, allergy.id, "inactive")
        assert updated.status == "inactive"

    def test_resolved_to_active_raises_state_transition_error(
        self, allergy_service, clinician_id, valid_allergy_payload
    ):
        """Reactivating a resolved allergy is forbidden; a new record must be created."""
        allergy = self._record(allergy_service, clinician_id, valid_allergy_payload)
        allergy_service.update_status(clinician_id, allergy.id, "resolved")
        with pytest.raises(StateTransitionError, match="resolved"):
            allergy_service.update_status(clinician_id, allergy.id, "active")

    def test_update_status_permission_denied(
        self,
        mock_allergy_repo,
        restrictive_permissions,
        mock_audit,
        clinician_id,
        valid_allergy_payload,
        permissive_permissions,
    ):
        """A user without write permission cannot change allergy status."""
        # record with permissive actor
        write_svc = AllergyIntoleranceService(
            mock_allergy_repo, permissive_permissions, mock_audit
        )
        allergy = write_svc.record_allergy(clinician_id, valid_allergy_payload)

        # attempt update with restrictive actor
        read_only_svc = AllergyIntoleranceService(
            mock_allergy_repo, restrictive_permissions, mock_audit
        )
        with pytest.raises(PermissionError):
            read_only_svc.update_status("reader-001", allergy.id, "inactive")

    def test_update_invalid_status_raises_validation_error(
        self, allergy_service, clinician_id, valid_allergy_payload
    ):
        """A status value outside the allowed vocabulary is rejected."""
        allergy = self._record(allergy_service, clinician_id, valid_allergy_payload)
        with pytest.raises(ValidationError, match="unknown-status"):
            allergy_service.update_status(clinician_id, allergy.id, "unknown-status")

    def test_update_nonexistent_allergy_raises_value_error(
        self, allergy_service, clinician_id
    ):
        """Updating a non-existent allergy raises ValueError."""
        with pytest.raises(ValueError, match="not found"):
            allergy_service.update_status(clinician_id, "nonexistent-id", "inactive")


