class TestMedicationRequestConflictDetection:
    """Tests that MedicationRequests carry conflict warnings when allergies match."""

    def _setup_allergy(self, allergy_service, clinician_id, payload) -> AllergyIntolerance:
        return allergy_service.record_allergy(clinician_id, payload)

    def test_no_conflict_when_no_allergies_recorded(
        self, med_service, clinician_id, valid_med_payload
    ):
        """No warnings are generated when the patient has no recorded allergies."""
        med_req = med_service.create_request(clinician_id, valid_med_payload)
        assert med_req.conflict_warnings == []

    def test_conflict_warning_generated_for_matching_allergy(
        self,
        allergy_service,
        med_service,
        clinician_id,
        valid_allergy_payload,
        valid_med_payload,
        mock_drug_db,
    ):
        """A conflict warning is attached when the medication matches a recorded allergy."""
        allergy = self._setup_allergy(allergy_service, clinician_id, valid_allergy_payload)
        # Simulate the drug DB reporting a high-severity interaction
        mock_drug_db.interaction_severity.return_value = "high"

        med_req = med_service.create_request(clinician_id, valid_med_payload)

        assert len(med_req.conflict_warnings) == 1
        warning = med_req.conflict_warnings[0]
        assert warning.allergy_id == allergy.id
        assert warning.medication_code == valid_med_payload["medication_code"]
        assert warning.severity == "high"

    def test_conflict_warning_contains_correct_allergy_reference(
        self,
        allergy_service,
        med_service,
        clinician_id,
        valid_allergy_payload,
        valid_med_payload,
        mock_drug_db,
    ):
        """The warning references the exact AllergyIntolerance ID that was recorded."""
        allergy = self._setup_allergy(allergy_service, clinician_id, valid_allergy_payload)
        mock_drug_db.interaction_severity.return_value = "moderate"

        med_req = med_service.create_request(clinician_id, valid_med_payload)
        assert med_req.conflict_warnings[0].allergy_id == allergy.id

    def test_no_conflict_warning_for_inactive_allergy(
        self,
        allergy_service,
        med_service,
        clinician_id,
        valid_allergy_payload,
        valid_med_payload,
        mock_drug_db,
    ):
        """An inactive allergy does NOT trigger a conflict warning."""
        allergy = self._setup_allergy(allergy_service, clinician_id, valid_allergy_payload)
        allergy_service.update_status(clinician_id, allergy.id, "inactive")
        mock_drug_db.interaction_severity.return_value = "high"

        med_req = med_service.create_request(clinician_id, valid_med_payload)
        assert med_req.conflict_warnings == []

    def test_no_conflict_warning_for_resolved_allergy(
        self,
        allergy_service,
        med_service,
        clinician_id,
        valid_allergy_payload,
        valid_med_payload,
        mock_drug_db,
    ):
        """A resolved allergy does NOT trigger a conflict warning."""
        allergy = self._setup_allergy(allergy_service, clinician_id, valid_allergy_payload)
        allergy_service.update_status(clinician_id, allergy.id, "resolved")
        mock_drug_db.interaction_severity.return_value = "high"

        med_req = med_service.create_request(clinician_id, valid_med_payload)
        assert med_req.conflict_warnings == []

    def test_multiple_allergies_produce_multiple_warnings(
        self,
        allergy_service,
        med_service,
        clinician_id,
        patient_id,
        valid_med_payload,
        mock_drug_db,
    ):
        """Multiple conflicting allergies each produce a separate warning."""
        payload_a = {
            "patient_id": patient_id,
            "substance_code": "7980",
            "substance_display": "Penicillin",
            "recorder_id": clinician_id,
        }
        payload_b = {
            "patient_id": patient_id,
            "substance_code": "41493",
            "substance_display": "Cephalosporins",
            "recorder_id": clinician_id,
        }
        allergy_service.record_allergy(clinician_id, payload_a)
        allergy_service.record_allergy(clinician_id, payload_b)
        mock_drug_db.interaction_severity.return_value = "moderate"

        med_req = med_service.create_request(clinician_id, valid_med_payload)
        assert len(med_req.conflict_warnings) == 2

    def test_non_interacting_drug_produces_no_warning(
        self,
        allergy_service,
        med_service,
